import asyncio
import websockets
import json
from collections import defaultdict

class Player:
    def __init__(self, username):
        self.username = username
        self.inventory = {}

    def add_item(self, item_id, amount):
        if item_id in self.inventory:
            self.inventory[item_id] += amount
        else:
            self.inventory[item_id] = amount

    def remove_item(self, item_id, amount):
        if item_id in self.inventory and self.inventory[item_id] >= amount:
            self.inventory[item_id] -= amount
            if self.inventory[item_id] == 0:
                del self.inventory[item_id]
            return True
        return False

class GameServer:
    def __init__(self):
        self.connected_players = {}
        self.lock = asyncio.Lock()

    async def handler(self, websocket, path):
        username = await websocket.recv()
        player = Player(username)
        self.connected_players[username] = player
        
        try:
            while True:
                message = await websocket.recv()
                await self.handle_message(player, message, websocket)
        except websockets.exceptions.ConnectionClosed:
            del self.connected_players[username]

    async def handle_message(self, player, message, websocket):
        data = json.loads(message)

        if data['action'] == 'trade':
            await self.handle_trade(player, data['recipient'], data['item_id'], data['amount'], websocket)

    async def handle_trade(self, player, recipient_username, item_id, amount, websocket):
        async with self.lock:
            recipient = self.connected_players.get(recipient_username)

            if recipient and player.remove_item(item_id, amount):
                recipient.add_item(item_id, amount)
                await websocket.send(json.dumps({'status': 'success', 'message': f'Traded {amount} of {item_id}'}))
                recipient_websocket = [ws for ws, p in self.connected_players.items() if p == recipient][0]
                await recipient_websocket.send(json.dumps({'status': 'success', 'message': f'You received {amount} of {item_id} from {player.username}'}))
            else:
                await websocket.send(json.dumps({'status': 'error', 'message': 'Trade failed'}))

    async def start_server(self):
        async with websockets.serve(self.handler, "localhost", 6789):
            await asyncio.Future()

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.start_server())